+    fn telemetry_no_refill_on_backward_time() {
+        let mut b = TokenBucket::with_time(10.0, 5.0, 1000);
+        b.try_acquire_one(500); // backward time → no refill
+        let t = b.telemetry();
+        assert_eq!(t.refills, 0);
+    }
